using System.Net;
using System.Net.Http;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.HttpOverrides;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Http;

var builder = WebApplication.CreateBuilder(args);

// Breaking change 1 — ValidateScopes is now enabled by default in development.
// A singleton (ICacheService) was capturing a scoped service (IUserService),
// which will throw InvalidOperationException at startup.
// Fix: register both as scoped so the lifetimes are compatible.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Breaking change 2 — HttpClientFactory now uses SocketsHttpHandler by default.
// The cast to HttpClientHandler would throw InvalidCastException at runtime.
// Fix: use ConfigurePrimaryHttpMessageHandler to set the handler explicitly.
// This also resolves the CS0618 obsoletion warning for ConfigureHttpMessageHandlerBuilder.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// Breaking change 3 — ForwardedHeadersMiddleware now ignores X-Forwarded-*
// headers from proxies not in KnownProxies or KnownNetworks.
// Fix: add trusted proxy addresses. Replace the example address below
// with your actual reverse proxy IP(s).
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1")); // TODO: replace with actual proxy IP
});

// Breaking change 4 — HttpClientFactory now redacts all header values in
// Trace-level logs by default. Since this app relies on Trace-level logging
// to debug HTTP request headers, explicitly allowlist the non-sensitive
// headers you need to inspect.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(header =>
        header != "X-Request-Id"
        && header != "X-Correlation-Id"
        && header != "Cache-Control"
        && header != "Accept"
        && header != "Content-Type"));

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

